<template>
	<div
		ref="elementRef"
		:class="className"
		:style="{
  opacity: inView ? 1 : initialOpacity,
  transition: `opacity ${duration}ms ${easing}, filter ${duration}ms ${easing}`,
  filter: blur ? inView ? 'blur(0px)' : 'blur(10px)' : 'none'
}"
	>
		<slot />
	</div>
</template>

<script setup>
import { onMounted, onUnmounted, ref } from "vue";
const props = defineProps({
  blur: { type: Boolean, required: false, default: false },
  duration: { type: Number, required: false, default: 1e3 },
  easing: { type: String, required: false, default: "ease-out" },
  delay: { type: Number, required: false, default: 0 },
  threshold: { type: Number, required: false, default: 0.1 },
  initialOpacity: { type: Number, required: false, default: 0 },
  className: { type: String, required: false, default: "" }
});
const inView = ref(false);
const elementRef = ref(null);
let observer = null;
onMounted(() => {
  const element = elementRef.value;
  if (!element) return;
  observer = new IntersectionObserver(
    ([entry]) => {
      if (entry.isIntersecting) {
        observer?.unobserve(element);
        setTimeout(() => {
          inView.value = true;
        }, props.delay);
      }
    },
    { threshold: props.threshold }
  );
  observer.observe(element);
});
onUnmounted(() => {
  if (observer) {
    observer.disconnect();
  }
});
</script>
